files.content:
.shiki code {
  counter-reset: step;
  counter-increment: step 0;
}

.shiki .line {
  position: relative;
  z-index: 0;
}

.shiki code .line::before {
  content: counter(step);
  counter-increment: step;
  width: 1rem;
  margin-right: 1.5rem;
  display: inline-block;
  text-align: right;
  color: rgba(115, 138, 148, 0.4);
}

.shiki .highlighted-line {
  background-color: rgb(26, 68, 26);
  border-left: 3px solid green;
  margin-right: -1.5rem;
  padding-right: 1.5rem;
}

.shiki .highlighted-line::before {
  color: green;
  font-weight: 600;
}

pre.shiki:has(.focus-line) code > span:not(.focus-line) {
  filter: blur(3px);
  opacity: 0.4;
  transition:
    filter 0.3s ease,
    opacity 0.3s ease;
}

pre.shiki .focus-line {
  filter: blur(0px);
  opacity: 1;
}

pre.shiki:hover code > span:not(.focus-line) {
  filter: blur(0px);
  opacity: 1;
}

.shiki .diff.add,
.shiki .diff.remove {
  position: relative;
}

.shiki .diff.add::before {
  content: "+" !important;
}

.shiki .diff.add:after {
  content: "";
  position: absolute;
  top: 0;
  bottom: 0;
  left: -1rem;
  right: -1rem;
  background: rgb(34 197 94 / 0.15) !important;
  border-left: 1px solid rgb(34 197 94 / 0.8);
  z-index: -1;
}

.shiki .diff.remove:before {
  content: "-" !important;
}

.shiki .diff.remove:after {
  content: "";
  position: absolute;
  top: 0;
  bottom: 0;
  left: -1rem;
  right: -1rem;
  background: rgb(239 68 68 / 0.15) !important;
  border-left: 1px solid rgb(239 68 68 / 0.8);
  z-index: -1;
}

"use client";

import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip";
import { cn } from "@/lib/utils";
import { transformerNotationDiff } from "@shikijs/transformers";
import { Check, Copy, Ellipsis } from "lucide-react";
import { DynamicIcon, iconNames } from "lucide-react/dynamic";
import { useTheme } from "next-themes";
import { useEffect, useState } from "react";
import { bundledLanguages, bundledThemes, codeToHtml, DecorationItem } from "shiki";

import { copyToClipboard } from "@/lib/support/utils";
import "./code.css";

export type CodeBlockType = {
  code: string;
  language: keyof typeof bundledLanguages;
  fileName: string;
  icon?: (typeof iconNames)[number];
  focus?: string;
  highlight?: string;
  themes?: {
    light: keyof typeof bundledThemes;
    dark: keyof typeof bundledThemes;
  };
  expendable?: boolean;
};

interface Properties {
  [PropertyName: string]: boolean | number | string | null | undefined | Array<string | number>;
}

export type HighlightedCodesType = {
  code: string;
};

export function CodeBlock({ code, fileName, language, icon, themes, focus, highlight, expendable = false }: CodeBlockType) {
  const { resolvedTheme } = useTheme();
  const [highlightedCode, setHighlightedCode] = useState<string>("");
  const [hasCopied, setHasCopied] = useState(false);
  const [isExpanded, setIsExpanded] = useState(!expendable);

  useEffect(() => {
    if (hasCopied) {
      const timer = setTimeout(() => setHasCopied(false), 2000);
      return () => clearTimeout(timer);
    }
  }, [hasCopied]);

  function copyCommand() {
    if (!code) return;

    copyToClipboard(code);
    setHasCopied(true);
  }

  function validate(ranges?: string): void {
    if (!ranges?.trim()) return;

    const rangeArray = ranges.split(",");
    const pattern = /^(?:\d+|\d+-\d+)$/;

    rangeArray.forEach((string) => {
      if (!pattern.test(string)) {
        throw new Error(`expression is not valid for ${string}`);
      }
    });
  }

  function createDecoration(ranges?: string, properties?: Properties) {
    validate(ranges);
    const decorations: DecorationItem[] = [];
    const rangesArray = ranges?.split(",");

    rangesArray?.forEach((string) => {
      if (!string.includes("-")) {
        const line = Number(string) === 0 ? 1 : Number(string);
        decorations.push({
          start: { line: line - 1, character: 0 },
          end: { line: line - 1, character: -1 },
          properties: properties,
        });
        return;
      }

      const rangesArray = string.split("-");
      const start_line = Number(rangesArray[0]);
      const end_line = Number(rangesArray[1]);

      decorations.push({
        start: { line: start_line - 1, character: 0 },
        end: { line: end_line - 1, character: -1 },
        properties: properties,
      });
    });
    return decorations.filter((d) => d);
  }

  function generateDecorations(highlight?: string, focus?: string) {
    const focusDecorations = createDecoration(focus, { class: "focus-line" });
    const highlightedDecorations = createDecoration(highlight, { class: "highlighted-line" });

    return [...highlightedDecorations, ...focusDecorations];
  }

  useEffect(() => {
    const theme = resolvedTheme === "dark" ? "github-dark" : "github-light";

    async function loadHighlightedCode() {
      const highlighted = await codeToHtml(code, {
        lang: language,
        theme: themes ? (resolvedTheme === "dark" ? themes.dark : themes.light) : theme,
        defaultColor: resolvedTheme === "dark" ? "dark" : "light",
        decorations: generateDecorations(highlight, focus),
        transformers: [transformerNotationDiff()],
      });

      setHighlightedCode(highlighted);
    }

    loadHighlightedCode();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [resolvedTheme, code, language, themes, highlight, focus]);

  return (
    <div>
      <div className="overflow-x-auto relative bg-accent rounded-sm min-w-62.5">
        <div className="border-border/50 flex items-center gap-2 border-b px-2 py-1">
          <Badge variant="outline" className="rounded-sm px-3 py-1 text-sm">
            {icon && <DynamicIcon name={icon} className="h-6 w-5" />}
            {fileName}
          </Badge>
        </div>

        <div className={cn("", isExpanded ? "max-h-full" : "max-h-100 overflow-hidden")}>
          {highlightedCode ? (
            <div dangerouslySetInnerHTML={{ __html: highlightedCode }} />
          ) : (
            <pre>
              <code>{code}</code>
            </pre>
          )}
        </div>

        <Tooltip>
          <TooltipTrigger asChild>
            <Button
              data-slot="copy-button"
              size="icon"
              variant="ghost"
              className="absolute top-2 right-2 z-10 size-5 opacity-70 hover:opacity-100 focus-visible:opacity-100"
              onClick={copyCommand}
            >
              <span className="sr-only">Copy</span>
              {hasCopied ? <Check /> : <Copy />}
            </Button>
          </TooltipTrigger>
          <TooltipContent>{hasCopied ? "Copied" : "Copy to Clipboard"}</TooltipContent>
        </Tooltip>
      </div>

      {expendable && (
        <div className="flex items-center justify-between bg-muted text-muted-foreground p-2 rounded-b-sm">
          <Button
            size="sm"
            onClick={() => {
              setIsExpanded((old) => !old);
            }}
          >
            <span className="flex items-center justify-center gap-1">
              <Ellipsis />
              <span>{isExpanded ? "Collapse" : "See all"}</span>
            </span>
          </Button>
        </div>
      )}
    </div>
  );
}

"use client";

import { copyToClipboard } from "@/lib/support/utils";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Check, Copy, Terminal } from "lucide-react";
import { Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip";
import { Button } from "@/components/ui/button";
import { useCallback, useEffect, useMemo, useState } from "react";

export function CodeBlockCommand({
  npm,
  yarn,
  pnpm,
  bun,
}: React.ComponentProps<"pre"> & {
  npm?: string;
  yarn?: string;
  pnpm?: string;
  bun?: string;
}) {
  const [hasCopied, setHasCopied] = useState(false);
  const [packageManager, setPackageManager] = useState<"npm" | "yarn" | "pnpm" | "bun">("pnpm");

  useEffect(() => {
    if (hasCopied) {
      const timer = setTimeout(() => setHasCopied(false), 2000);
      return () => clearTimeout(timer);
    }
  }, [hasCopied]);

  const tabs = useMemo(() => {
    return {
      pnpm: pnpm,
      npm: npm,
      yarn: yarn,
      bun: bun,
    };
  }, [npm, pnpm, yarn, bun]);

  const copyCommand = useCallback(() => {
    const command = tabs[packageManager];

    if (!command) {
      return;
    }

    copyToClipboard(command);

    setHasCopied(true);
  }, [tabs, packageManager]);

  return (
    <div className="overflow-x-auto relative bg-accent rounded-md">
      <Tabs
        className="gap-0"
        defaultValue={pnpm ? "pnpm" : yarn ? "yarn" : bun ? "bun" : "npm"}
        onValueChange={(value) => {
          setPackageManager(value as "pnpm" | "npm" | "yarn" | "bun");
        }}
      >
        <div className="border-border/50 flex items-center gap-2 border-b px-3 py-1 min-w-62.5">
          <div className="flex size-4 items-center justify-center rounded-[1px] opacity-70">
            <Terminal className="text-code size-5" />
          </div>
          <TabsList className="rounded-none bg-transparent p-0">
            {Object.entries(tabs).map(([key, value]) => {
              return (
                value && (
                  <TabsTrigger
                    key={key}
                    value={key}
                    className="data-[state=active]:bg-accent data-[state=active]:border-input h-7 border border-transparent pt-0.5 data-[state=active]:shadow-none"
                  >
                    {key}
                  </TabsTrigger>
                )
              );
            })}
          </TabsList>
        </div>
        <div className="no-scrollbar overflow-x-auto">
          {Object.entries(tabs).map(([key, value]) => {
            return (
              <TabsContent key={key} value={key} className="mt-0 px-4 py-3.5">
                <pre>
                  <code className="relative font-mono text-sm leading-none" data-language="bash">
                    {value}
                  </code>
                </pre>
              </TabsContent>
            );
          })}
        </div>
      </Tabs>
      <Tooltip>
        <TooltipTrigger asChild>
          <Button
            data-slot="copy-button"
            size="icon"
            variant="ghost"
            className="absolute top-2 right-2 z-10 size-7 opacity-70 hover:opacity-100 focus-visible:opacity-100"
            onClick={copyCommand}
          >
            <span className="sr-only">Copy</span>
            {hasCopied ? <Check /> : <Copy />}
          </Button>
        </TooltipTrigger>
        <TooltipContent>{hasCopied ? "Copied" : "Copy to Clipboard"}</TooltipContent>
      </Tooltip>
    </div>
  );
}

"use client";

import { Button } from "@/components/ui/button";
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip";
import { copyToClipboard } from "@/lib/support/utils";
import { cn } from "@/lib/utils";
import { TabsContent } from "@radix-ui/react-tabs";
import { transformerNotationDiff } from "@shikijs/transformers";
import { Check, Copy, Ellipsis } from "lucide-react";
import { DynamicIcon, iconNames } from "lucide-react/dynamic";
import { useTheme } from "next-themes";
import { useEffect, useState } from "react";
import { bundledLanguages, bundledThemes, codeToHtml, DecorationItem } from "shiki";
import "./code.css";

export type CodeType = {
  code: string;
  language: keyof typeof bundledLanguages;
  fileName: string;
  icon?: (typeof iconNames)[number];
  focus?: string;
  highlight?: string;
  themes?: {
    light: keyof typeof bundledThemes;
    dark: keyof typeof bundledThemes;
  };
};

interface Properties {
  [PropertyName: string]: boolean | number | string | null | undefined | Array<string | number>;
}

export type HighlightedCodesType = {
  id: string | number;
  code: string;
};

export function CodeGroup({ codes, expendable = false }: { codes: CodeType[]; expendable?: boolean }) {
  const { resolvedTheme } = useTheme();
  const [HighlightedCodes, setHighlightedCodes] = useState<HighlightedCodesType[]>([]);
  const [activeCodeID, setActiveCodeID] = useState<number>(0);
  const [hasCopied, setHasCopied] = useState(false);
  const [isExpended, setIsExpended] = useState(expendable ? true : false);

  useEffect(() => {
    if (hasCopied) {
      const timer = setTimeout(() => setHasCopied(false), 2000);
      return () => clearTimeout(timer);
    }
  }, [hasCopied]);

  function copyCommand() {
    const code = codes.find((c, index) => {
      return activeCodeID === index;
    });
    if (!code) return;

    copyToClipboard(code.code);
    setHasCopied(true);
  }

  function validate(ranges?: string): void {
    if (!ranges?.trim()) return;

    const rangeArray = ranges.split(",");

    const pattern = /^(?:\d+|\d+-\d+)$/;

    rangeArray.forEach((string) => {
      if (!pattern.test(string)) {
        throw new Error(`expression is not valid for ${string}`);
      }
    });
  }

  function createDecoration(ranges?: string, properties?: Properties) {
    validate(ranges);
    const decorations: DecorationItem[] = [];
    const rangesArray = ranges?.split(",");

    rangesArray?.forEach((string) => {
      if (!string.includes("-")) {
        const line = Number(string) === 0 ? 1 : Number(string);
        decorations.push({
          start: { line: line - 1, character: 0 },
          end: { line: line - 1, character: -1 },
          properties: properties,
        });
        return;
      }

      const rangesArray = string.split("-");
      const start_line = Number(rangesArray[0]);
      const end_line = Number(rangesArray[1]);

      decorations.push({
        start: { line: start_line - 1, character: 0 },
        end: { line: end_line - 1, character: -1 },
        properties: properties,
      });
    });
    return decorations.filter((d) => d);
  }

  function generateDecorations(highlight?: string, fauces?: string) {
    const focus = createDecoration(fauces, { class: "focus-line" });
    const highlighted = createDecoration(highlight, { class: "highlighted-line" });

    return [...highlighted, ...focus];
  }

  useEffect(() => {
    const theme = resolvedTheme === "dark" ? "github-dark" : "github-light";

    async function loadHighlightedCode() {
      const highlighted: HighlightedCodesType[] = await Promise.all(
        codes.map(async (c, index) => {
          const html = await codeToHtml(c.code, {
            lang: c.language,
            theme: c.themes ? (resolvedTheme === "dark" ? c.themes.dark : c.themes.light) : theme,
            defaultColor: resolvedTheme === "dark" ? "dark" : "light",
            decorations: generateDecorations(c.highlight, c.focus),
            transformers: [transformerNotationDiff()],
          });

          return {
            id: index,
            code: html,
          };
        }),
      );
      setHighlightedCodes(highlighted);
    }
    loadHighlightedCode();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [resolvedTheme, codes]);

  return (
    <div>
      <div className="overflow-x-auto relative bg-accent rounded-sm min-w-62.5">
        <Tabs
          className="gap-0"
          defaultValue={"0"}
          onValueChange={(value) => {
            const code = codes.findIndex((c, index) => {
              return index === Number(value);
            });
            if (code !== -1) {
              setActiveCodeID(code);
            }
          }}
        >
          <div className="border-border/50 flex items-center gap-2 border-b px-3 py-1">
            <TabsList>
              {codes.map((h, index) => (
                <TabsTrigger key={index} value={index.toString()}>
                  {h.icon && <DynamicIcon name={h.icon} className="h-6 w-5" />}
                  {h.fileName}
                </TabsTrigger>
              ))}
            </TabsList>
          </div>
          <div className={cn(" ", isExpended ? "max-h-100" : "max-h-full")}>
            {HighlightedCodes.length > 0 ? (
              HighlightedCodes.map((h) => (
                <TabsContent key={h.id} value={h.id.toString()}>
                  <div dangerouslySetInnerHTML={{ __html: h.code }} />
                </TabsContent>
              ))
            ) : (
              <pre>
                <code>{codes[0].code}</code>
              </pre>
            )}
          </div>
        </Tabs>

        <Tooltip>
          <TooltipTrigger asChild>
            <Button
              data-slot="copy-button"
              size="icon"
              variant="ghost"
              className="absolute top-2 right-2 z-10 size-7 opacity-70 hover:opacity-100 focus-visible:opacity-100"
              onClick={copyCommand}
            >
              <span className="sr-only">Copy</span>
              {hasCopied ? <Check /> : <Copy />}
            </Button>
          </TooltipTrigger>
          <TooltipContent>{hasCopied ? "Copied" : "Copy to Clipboard"}</TooltipContent>
        </Tooltip>
      </div>
      <div className={cn("flex items-center justify-between bg-muted text-muted-foreground p-2 rounded-b-sm", !expendable && "hidden")}>
        <Button
          size="sm"
          onClick={() => {
            setIsExpended((old) => !old);
          }}
        >
          {isExpended ? (
            <span className="flex items-center justify-center gap-1">
              <Ellipsis />
              <span>See all</span>
            </span>
          ) : (
            <span className="flex items-center justify-center gap-1">
              <Ellipsis />
              <span>Collapse</span>
            </span>
          )}
        </Button>
      </div>
    </div>
  );
}
